triggers.update:
declare @current_statement varchar(MAX);
declare @TEMP table (EventType nvarchar(30), Parameters int, EventInfo nvarchar(4000)); insert into @TEMP EXEC('DBCC INPUTBUFFER(@@SPID) with NO_INFOMSGS'); select @current_statement = EventInfo from @TEMP;
declare @operation char(1) = (case when (select COUNT(*) from deleted) = 0 then 'I' else 'U' end);
declare @portal_user_id int; -- TODO: Add support
if @Operation = 'I' insert into PortalUserAudit (PortalUserID, LoginClientID, LoginId, PWord, Active, FirstName, MiddleName, LastName, EMail, MobilePhone, QuestionID, Answer, LastLogin, PwordChanged, Locale, ClientID, DefaultDatabaseID, BypassLDAP, LdapUserName, Flags, ChangedOn, Operation, Command, HostName, ChangedBySqlUser, ChangedByPortalUserID, CanAdministerUsers) select i.ID, i.LoginClientID, i.LoginId, i.PWord, i.Active, i.FirstName, i.MiddleName, i.LastName, i.EMail, i.MobilePhone, i.QuestionID, i.Answer, i.LastLogin, i.PwordChanged, i.Locale, i.ClientID, i.DefaultDatabaseID, i.BypassLDAP, i.LdapUserName, i.Flags, GETUTCDATE(), @operation, @current_statement, HOST_NAME(), SYSTEM_USER, @portal_user_id, i.CanAdministerUsers from inserted i else insert into PortalUserAudit (PortalUserID, LoginClientID, LoginId, PWord, Active, FirstName, MiddleName, LastName, EMail, MobilePhone, QuestionID, Answer, LastLogin, PwordChanged, Locale, ClientID, DefaultDatabaseID, BypassLDAP, LdapUserName, Flags, ChangedOn, Operation, Command, HostName, ChangedBySqlUser, ChangedByPortalUserID, CanAdministerUsers) select i.ID, i.LoginClientID, i.LoginId, i.PWord, i.Active, i.FirstName, i.MiddleName, i.LastName, i.EMail, i.MobilePhone, i.QuestionID, i.Answer, i.LastLogin, i.PwordChanged, i.Locale, i.ClientID, i.DefaultDatabaseID, i.BypassLDAP, i.LdapUserName, i.Flags, GETUTCDATE(), @operation, @current_statement, HOST_NAME(), SYSTEM_USER, @portal_user_id, i.CanAdministerUsers from inserted i join deleted d on i.ID = d.ID and COALESCE(i.LastLogin, '') = COALESCE(d.LastLogin, '') and ( COALESCE(i.PWord, '') <> COALESCE(d.PWord, '') or COALESCE(i.EMail, '') <> COALESCE(d.EMail, '') or COALESCE(i.Flags, 0) <> COALESCE(d.Flags, 0) or COALESCE(i.Active, '') <> COALESCE(d.Active, '') or COALESCE(i.QuestionID, 0) <> COALESCE(d.QuestionID, 0) or COALESCE(i.Locale, '') <> COALESCE(d.Locale, '') or COALESCE(i.ClientID, 0) <> COALESCE(d.ClientID, 0) or COALESCE(i.DefaultDatabaseID, 0) <> COALESCE(d.DefaultDatabaseID, 0) or COALESCE(i.BypassLdap, '') <> COALESCE(d.BypassLdap, '') or COALESCE(i.LoginClientID, 0) <> COALESCE(d.LoginClientID, 0) or COALESCE(i.MobilePhone, '') <> COALESCE(d.MobilePhone, '') or COALESCE(i.FirstName, '') <> COALESCE(d.FirstName, '') or COALESCE(i.MiddleName, '') <> COALESCE(d.MiddleName, '') or COALESCE(i.LastName, '') <> COALESCE(d.LastName, '') or COALESCE(i.LdapUserName, '') <> COALESCE(d.LdapUserName, '') or COALESCE(i.PwordChangedSameDayCount, 0) <> COALESCE(d.PwordChangedSameDayCount, 0) );

triggers.delete:
declare @current_statement varchar(MAX);
declare @TEMP table (EventType nvarchar(30), Parameters int, EventInfo nvarchar(4000)); insert into @TEMP EXEC('DBCC INPUTBUFFER(@@SPID) with NO_INFOMSGS'); select @current_statement = EventInfo from @TEMP;
declare @portal_user_id int; -- TODO: Add support
insert into PortalUserAudit (PortalUserID, LoginClientID, LoginId, PWord, Active, FirstName, MiddleName, LastName, EMail, MobilePhone, QuestionID, Answer, LastLogin, PwordChanged, Locale, ClientID, DefaultDatabaseID, BypassLDAP, LdapUserName, Flags, ChangedOn, Operation, Command, HostName, ChangedBySqlUser, ChangedByPortalUserID, CanAdministerUsers) select d.ID, d.LoginClientID, d.LoginId, d.PWord, d.Active, d.FirstName, d.MiddleName, d.LastName, d.EMail, d.MobilePhone, d.QuestionID, d.Answer, d.LastLogin, d.PwordChanged, d.Locale, d.ClientID, d.DefaultDatabaseID, d.BypassLDAP, d.LdapUserName, d.Flags, GETUTCDATE(), 'D', @current_statement, HOST_NAME(), SYSTEM_USER, @portal_user_id, d.CanAdministerUsers from deleted d;
